case class ConfigSetting(key: String, value: String)
case class ConfigResponse(success: Boolean, settings: List[ConfigSetting], error: Option[String])

object ConfigJsonProtocol extends DefaultJsonProtocol {
  implicit val configSettingFormat: RootJsonFormat[ConfigSetting] = jsonFormat2(ConfigSetting)
  implicit val configResponseFormat: RootJsonFormat[ConfigResponse] = jsonFormat3(ConfigResponse)
}

object XmlConfigParser {

  /**
   * Creates a secure SAXParserFactory that prevents XXE attacks by disabling:
   * - External general entities
   * - External parameter entities
   * - External DTDs
   * - XInclude processing
   */
  private def createSecureSAXParserFactory(): SAXParserFactory = {
    val factory = SAXParserFactory.newInstance()

    // Disable external entities to prevent XXE
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
    factory.setFeature("http://xml.org/sax/features/resolve-dtd-uris", false)

    // Disable XInclude processing
    factory.setXIncludeAware(false)

    // Namespace aware but not validating
    factory.setNamespaceAware(true)
    factory.setValidating(false)

    factory
  }

  /**
   * Safely parses XML string using a secure SAX parser that prevents XXE attacks.
   */
  def safeLoadString(xmlString: String): Try[Elem] = {
    Try {
      val factory = createSecureSAXParserFactory()
      val saxParser = factory.newSAXParser()
      val source = new InputSource(new StringReader(xmlString))
      XML.withSAXParser(saxParser).load(source)
    }
  }

  /**
   * Extracts configuration settings from a parsed XML element.
   * Supports nested configuration groups.
   *
   * Expected XML format:
   * <configuration>
   *   <setting key="db.host" value="localhost"/>
   *   <setting key="db.port">5432</setting>
   *   <group name="cache">
   *     <setting key="enabled" value="true"/>
   *     <setting key="ttl">3600</setting>
   *   </group>
   * </configuration>
   */
  def extractSettings(xml: Elem): List[ConfigSetting] = {
    extractSettingsFromNode(xml, prefix = "")
  }

  private def extractSettingsFromNode(node: Node, prefix: String): List[ConfigSetting] = {
    val settings = scala.collection.mutable.ListBuffer[ConfigSetting]()

    (node \ "setting").foreach { settingNode =>
      val key = (settingNode \@ "key").trim
      if (key.nonEmpty) {
        val fullKey = if (prefix.nonEmpty) s"$prefix.$key" else key
        val value = {
          val attrValue = (settingNode \@ "value").trim
          if (attrValue.nonEmpty) attrValue
          else settingNode.text.trim
        }
        settings += ConfigSetting(fullKey, value)
      }
    }

    (node \ "group").foreach { groupNode =>
      val groupName = (groupNode \@ "name").trim
      if (groupName.nonEmpty) {
        val groupPrefix = if (prefix.nonEmpty) s"$prefix.$groupName" else groupName
        settings ++= extractSettingsFromNode(groupNode, groupPrefix)
      }
    }

    settings.toList
  }

  /**
   * Parses XML configuration string and extracts all settings.
   * Returns a ConfigResponse with extracted settings or error information.
   */
  def parseConfiguration(xmlString: String): ConfigResponse = {
    if (xmlString == null || xmlString.trim.isEmpty) {
      return ConfigResponse(success = false, settings = List.empty, error = Some("Empty XML input"))
    }

    safeLoadString(xmlString) match {
      case Success(xml) =>
        try {
          val settings = extractSettings(xml)
          ConfigResponse(success = true, settings = settings, error = None)
        } catch {
          case e: Exception =>
            ConfigResponse(success = false, settings = List.empty, error = Some(s"Error extracting settings: ${e.getMessage}"))
        }
      case Failure(e) =>
        ConfigResponse(
          success = false,
          settings = List.empty,
          error = Some(s"XML parsing error: ${e.getMessage}")
        )
    }
  }
}

object ConfigManagementService extends App {

  import ConfigJsonProtocol._

  implicit val system: ActorSystem = ActorSystem("config-management")
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher

  val route: Route =
    pathPrefix("api") {
