                complete(ConfigResponse(success = true, settings = List.empty, error = None))
              case Failure(e) =>
                complete(StatusCodes.BadRequest -> ConfigResponse(
                  success = false,
                  settings = List.empty,
                  error = Some(s"Invalid XML: ${e.getMessage}")
